import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormGroup } from '@angular/forms';
import { MatSnackBar } from '@angular/material/snack-bar';
import { Router } from '@angular/router';
import { ApiService } from 'app/shared/services/api.service';
import { LocalStoreService } from 'app/shared/services/local-store.service';

@Component({
  selector: 'app-interest-charge-summary',
  templateUrl: './interest-charge-summary.component.html',
  styleUrls: ['./interest-charge-summary.component.scss']
})
export class InterestChargeSummaryComponent implements OnInit {
  interestForm: FormGroup;
  savingForm:FormGroup;
  loanForm:FormGroup;
  chargeFormIT: FormGroup;
  accountType: any;
  accountId: any;
  constructor(private ls: LocalStoreService,private snack: MatSnackBar,private api:ApiService,private router: Router, private formBuilder: FormBuilder) { }

  ngOnInit(): void {
    this.accountId = this.ls.getItem('accountId');
    this.accountType=this.ls.getItem('accountType');
    this.api.getChargeValues(this.accountId).subscribe(resp=>{
      console.log("backend resp",resp)
      this.check(resp === null)
      console.log("backend resp",resp.length)
     
      this.onChangeInterestCharge(resp.length);
      this.inCharge.patchValue(resp);

      
      
    
    })
    this.api.getIntrestValues(this.accountId).subscribe(resp=>{
      console.log("backend resp",resp)
      this.check1(resp === null)
      console.log("backend resp",resp.length);
       
     
  
      this.onChangeInterest(resp.length);
      this.in.patchValue(resp);
  

      
      
    
    })
  

    this.chargeFormIT = this.formBuilder.group({
      chargeIT: new FormArray([]),
    });
  
    this.interestForm = this.formBuilder.group({
      interest: new FormArray([]),
    });
    this.savingForm = this.formBuilder.group({
      saving: new FormArray([]),
    });

    this.loanForm = this.formBuilder.group({
      loan: new FormArray([]),
    });
    this.chargeFormIT = this.formBuilder.group({
      chargeIT: new FormArray([]),
    });
    
  }
  onChangeInterestCharge(e) {
    const numberOfItems = e || 0;
    if (this.inCharge.length < numberOfItems) {
      for (let i = this.inCharge.length; i < numberOfItems; i++) {
        this.inCharge.push(
          this.formBuilder.group({
           
            intrestType: [''],
  amount: [''],
  waiver: [false],
  accountId:[''],
  createdDate:[''],
  craetedBy:[''],
  lastModifiedDate:[''],
  lastModifiedBy:['']
          })
        );
      }
    } else {
      for (let i = this.inCharge.length; i >= numberOfItems; i--) {
        this.inCharge.removeAt(i);
      }
    }
  }
  assignAccountType(accountType) {
    this.accountType=accountType
  }
  onChangeInterest(e) {
    const numberOfItems = e || 0;
    if (this.in.length < numberOfItems) {
      for (let i = this.in.length; i < numberOfItems; i++) {
        this.in.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.in.length; i >= numberOfItems; i--) {
        this.in.removeAt(i);
      }
    }
  }
  onChangeSaving(e) {
    const numberOfItems = e || 0;
    if (this.is.length < numberOfItems) {
      for (let i = this.is.length; i < numberOfItems; i++) {
        this.is.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.is.length; i >= numberOfItems; i--) {
        this.is.removeAt(i);
      }
    }
  }
  onChangeLoan(e) {
    const numberOfItems = e || 0;
    if (this.iloan.length < numberOfItems) {
      for (let i = this.iloan.length; i < numberOfItems; i++) {
        this.iloan.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.iloan.length; i >= numberOfItems; i--) {
        this.iloan.removeAt(i);
      }
    }
  }
  // convenience getters for easy access to form fields
  get f() {
    return this.interestForm.controls;
  }
  get in() {
    return this.f.interest as FormArray;
  }
  get fs() {
    return this.savingForm.controls;
  }
  get is() {
    return this.fs.saving as FormArray;
  }
  get floan() {
    return this.loanForm.controls;
  }
  get iloan() {
    return this.floan.loan as FormArray;
  }
  get fCharge() {
    return this.chargeFormIT.controls;
  }
  get inCharge() {
    return this.fCharge.chargeIT as FormArray;
  }



  goBack() {
    this.router.navigate(["/home/application/enrichment/list"]);
  }

  onSubmit() {
  
      this.router.navigate(['/home/application/enrichment/list/:id']);
  }
  check(accountType){

    if(accountType){

      console.log(this.snack.open)
      this.snack.open('Charge detail is empty', 'Error', {
        duration: 4000,
        verticalPosition: 'top',
        horizontalPosition: 'right'
      });
    }
  }
  check1(accountType){

    if(accountType){

      console.log(this.snack.open)
      this.snack.open('Intrest detail is empty', 'Error', {
        duration: 4000,
        verticalPosition: 'top',
        horizontalPosition: 'right'
      });
    }
  }
  // check12(){
  //   console.log(this.snack.open)
  //   this.snack.open('Intrest detail is empty', 'Error', {
  //     duration: 4000,
  //     verticalPosition: 'top',
  //     horizontalPosition: 'right'
  //   });
  // }

  
}




