import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, Validators, FormArray } from '@angular/forms';
import { MatSnackBar } from '@angular/material/snack-bar';
import { AppConfirmService } from 'app/shared/services/app-confirm/app-confirm.service';
import { ApplicationEntryStageService } from 'app/shared/services/application-entry-stage.service';
import { ActivatedRoute, Router } from '@angular/router';
import { LocalStoreService } from 'app/shared/services/local-store.service';
import { AccountService } from '../../account.service';
import { DataService } from 'app/shared/services/data.service';
import { UrlService } from '../../url.service';
import { ApiService } from 'app/shared/services/api.service';

@Component({
  selector: 'app-mandate',
  templateUrl: './mandate.component.html',
  styleUrls: ['./mandate.component.scss']
})
export class MandateComponent implements OnInit {
  panelOpenState = false;
  submitted = false;
  formData = {}
  console = console;
  mandatesForms: FormGroup;
  accountId: any;
  navSubscription: any;
  routeparams: any;
  showEditOption: boolean = false;
  previousUrl: string = '';
  mandateOnLoad: any;
  arrayModeOfOperation: any;
  no_of_applicants: any;
  flag: boolean;
  no_of_sig: any;

  NoOfSignatories: any[] = [
    { count: 1 },
    { count: 2 },
   
];


  constructor(private router: Router, 
    private route: ActivatedRoute, 
    private urlService: UrlService, 
    private dataService: DataService, 
    private apiService: ApplicationEntryStageService, 
    private accountService: AccountService, 
    private ls: LocalStoreService, 
    private formBuilder: FormBuilder, 
    private confirmService: AppConfirmService, 
    private cdr: ChangeDetectorRef, 
    private snack: MatSnackBar, 
    private api: ApiService) { }

  ngOnInit() {
    this.accountId = this.ls.getItem('accountId');
    this.no_of_applicants = this.ls.getItem('NO_OF_APPLICANTS');
    console.log("no_of_applicants=",this.no_of_applicants);
    let isMandateScreen: boolean = JSON.parse(this.ls.getItem('ACC_MANDATE_DONE'));
    this.getModeOfOperation("opr_mode");
    this.urlService.previousUrl$
      .subscribe((previousUrl: string) => {
        this.previousUrl = previousUrl
      });

    if (this.accountId != null && isMandateScreen) {
      this.showEditOption = true;
      this.gettingMandateDetail();
    } else {
      this.showEditOption = false;
      this.buildMandateForm();
    }

  }

  gettingMandateDetail() {
    this.api.gettingMandateDetails(this.accountId)
      .subscribe((resp: any) => {
        this.mandateOnLoad = resp;
        console.log("All Transaction Details", resp);
        this.buildMandateForm(resp, true);
      });
  }

  buildMandateForm(data?, isResponse?:boolean) {
    this.mandatesForms = this.formBuilder.group({
      mandates: this.formBuilder.array([this.addMFormGroup()])
    });
     console.log(this.mandatesForms);
    if(isResponse){
      this.addMandateToFormGroup(data);
      this.m.patchValue(data);
    }
  }

  _keyPress(event: any) {
    const pattern = /[0-9]/;
    let inputChar = String.fromCharCode(event.charCode);
    if (!pattern.test(inputChar)) {
      event.preventDefault();
    }
  }

  _keyPress2(event: any) {
    //this.console.log("mandatesForms.get('totalSignaturesRequired')=", this.mandatesForms.get('totalSignaturesRequired'));
    console.log("event.key=",event.key, "no_of_applicants=",this.no_of_applicants);
    this.no_of_sig = event.key;
    if(event.key > this.no_of_applicants){
      console.log("no of signatories is more than no of applicants");
      this.flag=true;
    }
    else{
      this.flag=false;
    }
    this.console.log(this.flag);
    const pattern = /[0-9]/;
    let inputChar = String.fromCharCode(event.charCode);
    if (!pattern.test(inputChar)) {
      event.preventDefault();
    }
  }

  changeNoOfSignatories(event: any) {
    //this.console.log("mandatesForms.get('totalSignaturesRequired')=", this.mandatesForms.get('totalSignaturesRequired'));
    console.log("event.key=",event, "no_of_applicants=",this.no_of_applicants);
    this.no_of_sig = event.key;
    if(event.value > this.no_of_applicants){
      console.log("no of signatories is more than no of applicants");
      this.flag=true;
    }
    else{
      this.flag=false;
    }
    // this.console.log(this.flag);
    // const pattern = /[0-9]/;
    // let inputChar = String.fromCharCode(event.charCode);
    // if (!pattern.test(inputChar)) {
    //   event.preventDefault();
    // }
  }

  // convenience getters for easy access to form fields
  get f() { return this.mandatesForms.controls; }
  get m() { return this.f.mandates as FormArray; }


  onChangeApplicants(e) {
    console.log(e.value);
    const numberOfMandates = e.value || 0;
    if (this.m.length < numberOfMandates) {
      for (let i = this.m.length; i < numberOfMandates; i++) {
        this.m.push(this.formBuilder.group({
          mandateId: [null],
          productAccountId: [this.accountId],
          modeOfOperation: ['', Validators.required],
          amountFrom: ['', Validators.required],
          amountTo: ['', Validators.required],
          //totalSignaturesRequired: ['', Validators.required],
          totalSignaturesRequired: ['', [Validators.required, Validators.maxLength(1)]],
          remarks: ['', []],
        }));
      }
    } else {
      for (let i = this.m.length; i >= numberOfMandates; i--) {
        this.m.removeAt(i);
      }
    }
  }

  addMFormGroup(): FormGroup {
    return this.formBuilder.group({
      mandateId: [null],
      productAccountId: [this.accountId],
      modeOfOperation: ['', Validators.required],
      amountFrom: ['', Validators.required],
      amountTo: ['', Validators.required],
      totalSignaturesRequired: ['', Validators.required],
      remarks: ['', []],
    });
  }



  addFormGroup() {
    this.m.push(this.formBuilder.group({
      mandateId: [null],
      productAccountId: [this.accountId],
      modeOfOperation: ['', Validators.required],
      amountFrom: ['', Validators.required],
      amountTo: ['', Validators.required],
      totalSignaturesRequired: ['', Validators.required],
      remarks: ['', []],
    }));
  }

  addMandateToFormGroup(data?) {
    const numberOfItems = data.length;
    console.log("numberOfItems", numberOfItems);
    for (let index = 1; index < numberOfItems; index++) {
      this.m.push(this.formBuilder.group({
        mandateId: [null],
        productAccountId: [this.accountId],
        modeOfOperation: ['', Validators.required],
        amountFrom: ['', Validators.required],
        amountTo: ['', Validators.required],
        totalSignaturesRequired: ['', Validators.required],
        remarks: ['', []],
      }));
    }
  }

  onSubmit() {
    this.submitted = true;
    console.log('SUCCESS!! :-)\n\n', this.mandatesForms.value);
    this.apiService.saveMandateDetails(this.mandatesForms.value).subscribe((data: any) => {
      console.log(data);
      if (data === 200 || data !== null) {
        this.snack.open(' Mandate Details Saved!', 'OK', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
        this.ls.setItem('ACC_MANDATE_DONE', true);
        this.accountService.refresh.next();
        this.router.navigate([`/home/application/account-service/${this.accountId}`]);
      }
      else if (data === 500) {
        this.snack.open('Not able to connect to server!', 'INTERNAL SERVER ERROR', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
      }
    }, err => {
      console.log(err);
    });
    // this.apiService.createCustomerInformation(this.mandatesForms.value)
    //   .subscribe((data: any) => {
    //     console.log(data);
    //   }, err => {
    //     console.log(err);
    //   });

  }

  onReset() {
    // reset whole form back to initial state
    this.submitted = false;
    this.mandatesForms.reset();
    this.m.clear();
  }

  onClear() {
    // clear errors and reset ticket fields
    this.submitted = false;
    this.m.reset();
  }

  getModeOfOperation(key: string) {
    this.api.getDropDownValues(key).subscribe((data) => {
      this.arrayModeOfOperation = data;
    });
  }


  removeMandate(i: number) {
    console.log("i", i);
    console.log("id:::",this.m.at(i).get('mandateId').value)
    let mandateId = this.m.at(i).get('mandateId').value;
    this.confirmService
      .confirm({ title: "Confirm", message: "Are you sure want to remove?", ok: "Yes", cancel: "No" })
      .subscribe(res => {
        console.log("res:: removed ", res);
        if (res) {
          this.apiService.deleteMandateById(mandateId, 'ADMIN')
            .subscribe((data:any) => {
              console.log("data", data);
          },err=>{
            const control = <FormArray>this.mandatesForms.controls['mandates'];
            control.removeAt(i);
            if (err.status === 200) {
              this.snack.open('Record Deleted Successfully', 'OK', {
                duration: 4000,
                verticalPosition: 'top',
                horizontalPosition: 'right'
              });
            }
          });
        } else return;
      });
  }

  goBack() {
    this.router.navigate([this.previousUrl]);
  }

  ngOnDestroy(): void {
    //Called once, before the instance is destroyed.
    //Add 'implements OnDestroy' to the class.
    this.dataService.sendNavParam({});
  }
}
