import { Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, FormArray } from "@angular/forms";
import { MatDialogRef } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { Router } from '@angular/router';
import { ApiService } from 'app/shared/services/api.service';
import { LocalStoreService } from 'app/shared/services/local-store.service';

@Component({
  selector: 'app-intrest-details-summary',
  templateUrl: './intrest-details-summary.component.html',
  styleUrls: ['./intrest-details-summary.component.scss']
})
export class IntrestDetailsSummaryComponent implements OnInit {
  interestForm: FormGroup;
  savingForm:FormGroup;
  loanForm:FormGroup;
  accountType: any;
  accountId:any;
  constructor( private ls: LocalStoreService,private snack: MatSnackBar,private dialogRef: MatDialogRef<IntrestDetailsSummaryComponent>,private api:ApiService,private router: Router, private formBuilder: FormBuilder) { }

  ngOnInit(): void {
    this.accountId = this.ls.getItem('accountId');
    this.accountType=this.ls.getItem('accountType');
    this.api.getIntrestValues(this.accountId).subscribe(resp=>{
      console.log("backend resp",resp)
      this.check(resp=== null)
      console.log("backend resp",resp.length);
       
       
      // const filteredResponse = resp.filter(res => res.intrestType === 'fixed');
       this.onChangeInterest(resp.length);
      this.in.patchValue(resp);
     
      // const filteredResponseSave = resp.filter(res => res.intrestType === 'savings');
      // this.onChangeSaving(filteredResponseSave.length);
      // this.is.patchValue(filteredResponseSave);

      // const filteredResponseLoan = resp.filter(res => res.intrestType === 'loan');
      // this.onChangeLoan(filteredResponseLoan.length);
      // this.iloan.patchValue(filteredResponseLoan);

      
      
    
    })
    
    this.interestForm = this.formBuilder.group({
      interest: new FormArray([]),
    });
    this.savingForm = this.formBuilder.group({
      saving: new FormArray([]),
    });

    this.loanForm = this.formBuilder.group({
      loan: new FormArray([]),
    });

    
  }
  assignAccountType(accountType) {
    this.accountType=accountType
  }

  onChangeInterest(e) {
    const numberOfItems = e || 0;
    if (this.in.length < numberOfItems) {
      for (let i = this.in.length; i < numberOfItems; i++) {
        this.in.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.in.length; i >= numberOfItems; i--) {
        this.in.removeAt(i);
      }
    }
  }
  onChangeSaving(e) {
    const numberOfItems = e || 0;
    if (this.is.length < numberOfItems) {
      for (let i = this.is.length; i < numberOfItems; i++) {
        this.is.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.is.length; i >= numberOfItems; i--) {
        this.is.removeAt(i);
      }
    }
  }
  onChangeLoan(e) {
    const numberOfItems = e || 0;
    if (this.iloan.length < numberOfItems) {
      for (let i = this.iloan.length; i < numberOfItems; i++) {
        this.iloan.push(
          this.formBuilder.group({
           
            intrestType: [""],
            intrestRateApplicable: [""],
            marginIn: [""],
            effectiveRate: [""],
            accountId: [this.accountId],
            createdDate: [""],
            createdBy: [""],
            lastModifiedDate: [""],
            lastModifiedBy: [""],
          })
        );
      }
    } else {
      for (let i = this.iloan.length; i >= numberOfItems; i--) {
        this.iloan.removeAt(i);
      }
    }
  }
  // convenience getters for easy access to form fields
  get f() {
    return this.interestForm.controls;
  }
  get in() {
    return this.f.interest as FormArray;
  }
  get fs() {
    return this.savingForm.controls;
  }
  get is() {
    return this.fs.saving as FormArray;
  }
  get floan() {
    return this.loanForm.controls;
  }
  get iloan() {
    return this.floan.loan as FormArray;
  }


  goBack() {
    this.router.navigate(["/home/application/enrichment/list"]);
  }

  onSubmit(form) {
    console.log("form", form.interest);
    console.log("form value", form);
    console.log("form value", this.interestForm.value);
    this.api.intrestDetailsSave(form.interest).subscribe(resp=>{
      console.log("backend response from intrest saving",resp)
    }
      
      )
      this.router.navigate(['/home/application/enrichment/charge']);
  }
  edit()
  {
    this.dialogRef.close();
    this.api.setFlag({
      flag:true
    })
    this.router.navigate([`/home/application/enrichment/interestEdit/${this.accountId}`]);
  }
  check(accountType){

    if(accountType){

      console.log(this.snack.open)
      this.snack.open('Intrest detail is empty', 'Error', {
        duration: 4000,
        verticalPosition: 'top',
        horizontalPosition: 'right'
      });
    }
  }
}
